/**
 * @file bench_pcap.c
 * @brief Benchmark: DFA traversal on raw payload files from traffic generator.
 *
 * Reads binary payload files (generated by gen_traffic.py via scapy)
 * and feeds them through the full pipeline. Each file contains
 * back-to-back payloads: [uint32_t len][len bytes][uint32_t len]...
 *
 * @author Kiran P Das
 * @date 2026-02-21
 * @version 0.0.1
 * @copyright Copyright (c) 2026 ZDPI Project. Licensed under GPL v3.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <stdint.h>

#include "zdpi_types.h"
#include "regex_parser.h"
#include "nfa.h"
#include "dfa.h"
#include "ec_compress.h"
#include "linearize.h"

#define WARMUP_RUNS 5
#define TRAVERSE_RUNS 100

static double time_diff_ms(struct timespec *start, struct timespec *end)
{
	return (end->tv_sec - start->tv_sec) * 1000.0 +
	       (end->tv_nsec - start->tv_nsec) / 1e6;
}

static double time_diff_us(struct timespec *start, struct timespec *end)
{
	return (end->tv_sec - start->tv_sec) * 1e6 +
	       (end->tv_nsec - start->tv_nsec) / 1e3;
}

/* Realistic patterns from Snort/ET community rules */
static const char *default_patterns[] = {
	".*\\.\\./.*",
	".*etc/passwd.*",
	".*cmd\\.exe.*",
	".*<script.*",
	".*UNION.*SELECT.*",
	".*javascript:.*",
	".*eval\\(.*",
	".*exec\\(.*",
	".*system\\(.*",
	".*onerror.*",
};
#define NUM_DEFAULT_PATTERNS \
	(sizeof(default_patterns) / sizeof(default_patterns[0]))

struct payload_set {
	uint8_t **payloads;
	uint32_t *lengths;
	uint32_t count;
	uint64_t total_bytes;
	char name[256];
};

static void payload_set_free(struct payload_set *ps)
{
	for (uint32_t i = 0; i < ps->count; i++)
		free(ps->payloads[i]);
	free(ps->payloads);
	free(ps->lengths);
	ps->count = 0;
}

static int load_payload_file(const char *path, struct payload_set *ps)
{
	FILE *f = fopen(path, "rb");
	if (!f) {
		fprintf(stderr, "Cannot open %s\n", path);
		return -1;
	}

	/* Extract filename for labeling */
	const char *basename = strrchr(path, '/');
	basename = basename ? basename + 1 : path;
	snprintf(ps->name, sizeof(ps->name), "%s", basename);
	/* Remove extension */
	char *dot = strrchr(ps->name, '.');
	if (dot)
		*dot = '\0';

	uint32_t cap = 1024;
	ps->payloads = malloc(cap * sizeof(uint8_t *));
	ps->lengths = malloc(cap * sizeof(uint32_t));
	ps->count = 0;
	ps->total_bytes = 0;

	while (!feof(f)) {
		uint32_t len;
		if (fread(&len, sizeof(len), 1, f) != 1)
			break;

		if (len > 65536) {
			fprintf(stderr, "Payload too large: %u\n", len);
			break;
		}

		uint8_t *buf = malloc(len);
		if (!buf)
			break;

		if (fread(buf, 1, len, f) != len) {
			free(buf);
			break;
		}

		if (ps->count >= cap) {
			cap *= 2;
			ps->payloads =
				realloc(ps->payloads,
					cap * sizeof(uint8_t *));
			ps->lengths =
				realloc(ps->lengths,
					cap * sizeof(uint32_t));
		}

		ps->payloads[ps->count] = buf;
		ps->lengths[ps->count] = len;
		ps->total_bytes += len;
		ps->count++;
	}

	fclose(f);
	return 0;
}

static int build_dfa_blob(const char **patterns, uint32_t n,
			  struct arena_blob *blob)
{
	struct re_token_stream *streams = calloc(n, sizeof(*streams));
	uint32_t *rule_ids = calloc(n, sizeof(*rule_ids));
	if (!streams || !rule_ids) {
		free(streams);
		free(rule_ids);
		return ZDPI_ERR_NOMEM;
	}

	for (uint32_t i = 0; i < n; i++) {
		int rc = regex_parse(patterns[i], &streams[i]);
		if (rc) {
			free(streams);
			free(rule_ids);
			return rc;
		}
		rule_ids[i] = i + 1;
	}

	struct nfa nfa_g;
	struct dfa dfa_g;
	struct ec_map ecm;
	struct ec_table ect;
	int rc;

	rc = nfa_alloc(&nfa_g, NFA_DEFAULT_CAPACITY);
	if (rc) {
		free(streams);
		free(rule_ids);
		return rc;
	}

	if (n == 1)
		rc = nfa_build(&streams[0], &nfa_g);
	else
		rc = nfa_build_union(streams, n, rule_ids, &nfa_g);
	free(streams);
	free(rule_ids);
	if (rc) {
		nfa_free(&nfa_g);
		return rc;
	}

	rc = dfa_alloc(&dfa_g, ZDPI_MAX_STATES);
	if (rc) {
		nfa_free(&nfa_g);
		return rc;
	}
	rc = dfa_build(&nfa_g, &dfa_g);
	nfa_free(&nfa_g);
	if (rc) {
		dfa_free(&dfa_g);
		return rc;
	}
	rc = dfa_minimize(&dfa_g);
	if (rc) {
		dfa_free(&dfa_g);
		return rc;
	}
	rc = ec_compute(&dfa_g, &ecm);
	if (rc) {
		dfa_free(&dfa_g);
		return rc;
	}
	rc = ec_table_build(&dfa_g, &ecm, &ect);
	if (rc) {
		dfa_free(&dfa_g);
		return rc;
	}
	rc = linearize(&ecm, &ect, blob);
	dfa_free(&dfa_g);
	ec_table_free(&ect);
	return rc;
}

static void bench_payload_set(struct payload_set *ps, struct arena_blob *blob)
{
	if (ps->count == 0) {
		fprintf(stderr, "  %s: empty, skipping\n", ps->name);
		return;
	}

	fprintf(stderr, "  %s: %u payloads, %lu bytes total\n",
		ps->name, ps->count, (unsigned long)ps->total_bytes);

	for (int iter = 0; iter < WARMUP_RUNS + TRAVERSE_RUNS; iter++) {
		struct timespec t0, t1;
		uint32_t drops = 0;
		uint32_t passes = 0;

		clock_gettime(CLOCK_MONOTONIC, &t0);
		for (uint32_t i = 0; i < ps->count; i++) {
			int act = linearize_simulate(blob, ps->payloads[i],
						     ps->lengths[i]);
			if (act == ZDPI_ACTION_DROP)
				drops++;
			else
				passes++;
		}
		clock_gettime(CLOCK_MONOTONIC, &t1);

		if (iter < WARMUP_RUNS)
			continue;

		int run = iter - WARMUP_RUNS;
		double elapsed_us = time_diff_us(&t0, &t1);
		double mb_per_sec =
			(double)ps->total_bytes / elapsed_us;
		double pkts_per_sec =
			(double)ps->count / (elapsed_us / 1e6);
		double ns_per_pkt =
			elapsed_us * 1e3 / ps->count;

		printf("pcap_traverse,%s_time_ms,%s,%d,%.4f\n",
		       ps->name, ps->name, run,
		       time_diff_ms(&t0, &t1));
		printf("pcap_throughput,%s_MBps,%s,%d,%.2f\n",
		       ps->name, ps->name, run, mb_per_sec);
		printf("pcap_pps,%s_pkts_per_sec,%s,%d,%.0f\n",
		       ps->name, ps->name, run, pkts_per_sec);
		printf("pcap_latency,%s_ns_per_pkt,%s,%d,%.2f\n",
		       ps->name, ps->name, run, ns_per_pkt);

		if (run == 0) {
			printf("pcap_drops,%s_drop_count,%s,0,%u\n",
			       ps->name, ps->name, drops);
			printf("pcap_passes,%s_pass_count,%s,0,%u\n",
			       ps->name, ps->name, passes);
			printf("pcap_drop_rate,%s_drop_pct,%s,0,%.2f\n",
			       ps->name, ps->name,
			       100.0 * drops / ps->count);
		}
	}
}

int main(int argc, char *argv[])
{
	if (argc < 2) {
		fprintf(stderr,
			"Usage: %s <payload_file> [payload_file ...]\n"
			"\n"
			"Payload files are binary: [u32 len][bytes]...\n"
			"Generate with: python3 gen_traffic.py\n",
			argv[0]);
		return 1;
	}

	printf("test,description,variant,run,value\n");

	/* Build DFA from default patterns */
	struct arena_blob blob;
	int rc = build_dfa_blob(default_patterns, NUM_DEFAULT_PATTERNS,
				&blob);
	if (rc) {
		fprintf(stderr, "Failed to build DFA: %d\n", rc);
		return 1;
	}
	fprintf(stderr, "DFA built: %u rules, blob %u bytes\n",
		(uint32_t)NUM_DEFAULT_PATTERNS, blob.size);

	for (int i = 1; i < argc; i++) {
		struct payload_set ps = { 0 };
		if (load_payload_file(argv[i], &ps) == 0) {
			bench_payload_set(&ps, &blob);
			payload_set_free(&ps);
		}
	}

	arena_blob_free(&blob);
	return 0;
}
